
INSERT INTO public.opportunities (title, category, description, revenue_estimate, downloads, market_size, growth_percent, competition_score, opportunity_score, growth_velocity, is_hidden_gem, tags) VALUES

-- ── Telehealth & Virtual Care ──
('AI Primary Care Platform', 'Health', 'On-demand primary care visits via chat and video with AI pre-triage reducing physician time per consult 60%. Teladoc revenue $2.6B; AI-first approach cuts cost per visit to $15 vs $79 industry average.', '$20k–$150k MRR', '200k+/mo', '$18.5B', 88, 42, 93, 'Explosive', true, ARRAY['telehealth','AI','primary-care','virtual']),
('Mental Health Telehealth for Teens', 'Health', 'On-demand therapy and psychiatry for 13-17 year olds with parental dashboard. Teen mental health crisis drove 200% app download growth since 2020; BetterHelp does not serve under-18.', '$10k–$65k MRR', '150k+/mo', '$6.8B', 85, 40, 92, 'Explosive', true, ARRAY['telehealth','mental-health','teens','therapy']),
('Chronic Disease Remote Monitoring', 'Health', 'Continuous vitals monitoring for diabetes, hypertension, and heart failure patients via wearable + AI. CMS now reimburses RPM at $100+/patient/month; 60M Americans have qualifying conditions.', '$15k–$100k MRR', '80k+/mo', '$12.0B', 82, 38, 92, 'Explosive', true, ARRAY['telehealth','RPM','chronic-disease','wearable']),
('AI Dermatology Triage App', 'Health', 'Photo-based skin condition assessment routing to OTC treatment or derm consult. 50M Americans visit dermatologists annually; 85% of cases could be triaged digitally saving $4.5B.', '$8k–$50k MRR', '300k+/mo', '$5.5B', 78, 44, 88, 'Rising', true, ARRAY['telehealth','dermatology','AI','triage']),
('Second Opinion Telemedicine Platform', 'Health', 'Connect patients with top specialists for second opinions on diagnoses within 48 hours. 12M Americans seek second opinions annually; misdiagnosis costs $100B+ in unnecessary treatment.', '$10k–$65k MRR', '50k+/mo', '$4.5B', 76, 40, 88, 'Rising', true, ARRAY['telehealth','second-opinion','specialist','diagnosis']),
('Pediatric Telehealth for Parents', 'Health', 'On-demand pediatric care via video with AI symptom checker for children 0-12. Parents average 4 urgent pediatric visits/year; 60% happen after-hours when offices are closed.', '$8k–$50k MRR', '400k+/mo', '$5.8B', 80, 42, 89, 'Explosive', false, ARRAY['telehealth','pediatric','parents','AI']),

-- ── Mental Health ──
('AI-Powered CBT Therapy App', 'Health', 'Structured cognitive behavioral therapy delivered by AI with licensed therapist escalation. Woebot raised $90M; clinical evidence shows AI CBT matches therapist outcomes for mild-moderate depression.', '$5k–$30k MRR', '1.5M+/mo', '$8.0B', 78, 52, 87, 'Rising', false, ARRAY['mental-health','CBT','AI','therapy']),
('Burnout Prevention Platform for Clinicians', 'Health', 'Real-time burnout risk scoring and micro-intervention tool for healthcare workers. 60% of physicians report burnout; $17B annual cost to health systems from turnover and errors.', '$12k–$80k MRR', '30k+/mo', '$6.5B', 82, 36, 92, 'Explosive', true, ARRAY['mental-health','burnout','clinicians','B2B']),
('Trauma-Informed Care App', 'Health', 'EMDR-guided self-help app with therapist monitoring portal for PTSD and complex trauma. 70% of adults experience trauma; only 8% receive EMDR despite being gold-standard treatment.', '$4k–$24k MRR', '400k+/mo', '$3.8B', 74, 45, 85, 'Rising', true, ARRAY['mental-health','trauma','EMDR','PTSD']),
('Substance Abuse Recovery App', 'Health', 'Peer accountability, craving journal, and telehealth MAT prescriptions for addiction recovery. 48M Americans have substance use disorder; only 11% receive treatment; digital pathways reduce barriers.', '$6k–$38k MRR', '300k+/mo', '$5.2B', 76, 42, 87, 'Rising', true, ARRAY['mental-health','addiction','recovery','MAT']),
('Corporate Mental Health Benefits Platform', 'Health', 'Employer-sponsored mental health navigation with therapy matching and utilization analytics. 91% of employers now offer EAP; <5% utilization rate signals massive engagement gap.', '$12k–$80k MRR', '25k+/mo', '$7.5B', 80, 44, 89, 'Rising', true, ARRAY['mental-health','corporate','EAP','benefits']),

-- ── Women''s Health ──
('AI Menopause Management Platform', 'Health', 'Symptom tracking, HRT prescriptions, and personalized coaching for perimenopause and menopause. 50M US women in menopause; $600B market largely ignored by mainstream health tech until 2022.', '$12k–$80k MRR', '200k+/mo', '$7.5B', 88, 35, 94, 'Explosive', true, ARRAY['womens-health','menopause','HRT','telehealth']),
('Endometriosis Diagnosis & Management App', 'Health', 'Symptom diary, specialist finder, and AI-guided treatment pathways for endometriosis. 190M women affected globally; average diagnosis takes 7-10 years; no dedicated digital health tool.', '$5k–$30k MRR', '500k+/mo', '$4.2B', 82, 34, 92, 'Explosive', true, ARRAY['womens-health','endometriosis','diagnosis','chronic']),
('Postpartum Mental Health Platform', 'Health', 'Screening, therapy access, and peer support for postpartum depression and anxiety. 1 in 5 new mothers experiences PPD; most cases go undetected; $6B in lost productivity annually.', '$6k–$40k MRR', '300k+/mo', '$4.8B', 78, 38, 90, 'Rising', true, ARRAY['womens-health','postpartum','mental-health','new-moms']),
('Pelvic Floor Health App', 'Health', 'Guided pelvic floor exercises, biofeedback integration, and PT telehealth for incontinence. 25M American women have urinary incontinence; 70% never seek treatment due to stigma.', '$4k–$24k MRR', '600k+/mo', '$3.5B', 76, 36, 89, 'Rising', true, ARRAY['womens-health','pelvic-floor','PT','incontinence']),
('PCOS Management & Fertility App', 'Health', 'Cycle tracking, insulin resistance coaching, and fertility optimization for PCOS patients. 10% of women globally have PCOS; first-line treatment is lifestyle change with no dedicated app.', '$4k–$22k MRR', '800k+/mo', '$3.8B', 76, 42, 87, 'Rising', true, ARRAY['womens-health','PCOS','fertility','hormones']),

