('AI Fall Detection & Prevention Platform', 'Health', 'Passive fall detection via ambient sensors with predictive risk scoring and family alerts. Falls cost Medicare $50B annually; 800k hospitalizations/yr; every 11 seconds a senior falls.', '$10k–$65k MRR', '100k+/mo', '$8.5B', 84, 38, 92, 'Explosive', true, ARRAY['senior-care','fall-detection','AI','safety']),
('Dementia Care Coordination Platform', 'Health', 'Family caregiver tools, medication reminders, and professional care team coordination for dementia. 6.7M Americans have Alzheimer; 11M unpaid caregivers need digital support infrastructure.', '$8k–$50k MRR', '150k+/mo', '$6.8B', 80, 40, 91, 'Explosive', true, ARRAY['senior-care','dementia','caregiving','family']),
('Social Isolation Detection for Seniors', 'Health', 'Passive monitoring of daily activity patterns to detect isolation and trigger outreach. Loneliness equivalent to smoking 15 cigarettes/day; 26% of seniors live alone with no digital support.', '$6k–$38k MRR', '80k+/mo', '$4.5B', 78, 36, 90, 'Rising', true, ARRAY['senior-care','isolation','monitoring','AI']),
('Senior Medication Adherence Platform', 'Health', 'Smart pill dispenser + app with caregiver alerts and pharmacist telehealth for seniors. Medication non-adherence causes 125k US deaths annually and $300B in preventable costs.', '$8k–$50k MRR', '120k+/mo', '$5.5B', 80, 40, 90, 'Explosive', true, ARRAY['senior-care','medication','adherence','IoT']),
('Aging-in-Place Technology Platform', 'Health', 'Bundles smart home sensors, telehealth, and emergency response for independent seniors. 90% of seniors want to age at home; average nursing home costs $9,000/month vs $500/month for tech.', '$10k–$65k MRR', '60k+/mo', '$9.0B', 82, 38, 92, 'Explosive', true, ARRAY['senior-care','aging-in-place','smart-home','telehealth']),

