('Prior Authorization Automation Platform', 'Health', 'AI submits and tracks prior auth requests reducing approval time from days to hours. Prior auth denials cost US healthcare $350B; physicians spend 2+ hours daily on PA paperwork.', '$12k–$80k MRR', '8k+/mo', '$8.5B', 82, 36, 93, 'Explosive', true, ARRAY['healthcare-ops','prior-auth','AI','insurance']),
('Clinical Documentation AI Assistant', 'Health', 'Ambient listening AI transcribes patient encounters directly into structured EHR notes. Physicians spend 50% of time on documentation; Nuance DAX is enterprise-only at $2k+/provider/month.', '$15k–$100k MRR', '10k+/mo', '$9.0B', 86, 40, 93, 'Explosive', true, ARRAY['healthcare-ops','documentation','AI','EHR']),
('Healthcare Staff Scheduling Optimization', 'Health', 'AI-optimized nurse and physician scheduling reducing overtime costs and burnout. US nursing shortage at 200k; poor scheduling causes $9B in overtime annually for health systems.', '$10k–$65k MRR', '3k+/mo', '$6.0B', 78, 40, 89, 'Rising', true, ARRAY['healthcare-ops','scheduling','AI','nursing']),
('Patient Discharge Planning AI', 'Health', 'Predicts readmission risk and automates post-discharge care coordination. 30-day hospital readmissions cost Medicare $26B annually; CMS penalizes hospitals for excess readmissions.', '$12k–$80k MRR', '2k+/mo', '$7.5B', 80, 36, 92, 'Explosive', true, ARRAY['healthcare-ops','discharge','readmission','AI']),
('Dental Practice AI Receptionist', 'Health', 'AI handles appointment booking, insurance verification, and recall campaigns for dental offices. 200k+ US dental practices each spending $80k/yr on front desk staff; 80% routine tasks automatable.', '$4k–$24k MRR', '30k+/mo', '$4.5B', 76, 42, 87, 'Rising', true, ARRAY['healthcare-ops','dental','AI','scheduling']),

